except FileNotFoundError:
    print('Dosya bulunamadı')
finally:
    dosya.close()  # Kaynak temizleme

# else bloğu - hata yoksa çalışır
try:
    sayi = int(input('Sayı gir: '))
except ValueError:
    print('Geçersiz sayı!')
