```python
from functools import wraps
import time
from typing import Callable, Any

# Temel decorator
def basit_decorator(fonksiyon):
    @wraps(fonksiyon)
    def wrapper(*args, **kwargs):
        print('Fonksiyon öncesi')
        sonuc = fonksiyon(*args, **kwargs)
        print('Fonksiyon sonrası')
        return sonuc
    return wrapper

@basit_decorator
def selamla(isim):
    return f'Merhaba {isim}!'

# Parametreli decorator
def tekrar(sayi: int):
    def decorator(fonksiyon):
        @wraps(fonksiyon)
        def wrapper(*args, **kwargs):
            sonuclar = []
            for _ in range(sayi):
                sonuclar.append(fonksiyon(*args, **kwargs))
            return sonuclar
        return wrapper
    return decorator

@tekrar(3)
def merhaba():
    return 'Merhaba'

# Süre ölçen decorator
def sure_olc(fonksiyon: Callable) -> Callable:
    @wraps(fonksiyon)
    def wrapper(*args, **kwargs) -> Any:
        baslangic = time.perf_counter()
        sonuc = fonksiyon(*args, **kwargs)
        bitis = time.perf_counter()
        print(f'{fonksiyon.__name__} {bitis - baslangic:.4f} saniye sürdü')
        return sonuc
    return wrapper

# Cache decorator
def cache(fonksiyon):
    _cache = {}

    @wraps(fonksiyon)
    def wrapper(*args):
        if args in _cache:
            print('Cache\'ten alındı')
            return _cache[args]
        sonuc = fonksiyon(*args)
        _cache[args] = sonuc
        return sonuc
    return wrapper

@cache
def fib(n: int) -> int:
    if n < 2:
        return n
    return fib(n-1) + fib(n-2)

# Class decorator
class Sayac:
    def __init__(self, fonksiyon):
        self.fonksiyon = fonksiyon
        self.sayac = 0

    def __call__(self, *args, **kwargs):
        self.sayac += 1
        print(f'{self.fonksiyon.__name__} {self.sayac}. kez çağrıldı')
        return self.fonksiyon(*args, **kwargs)

@Sayac
def topla(a, b):
    return a + b

# Property decorator örneği
class Dikdortgen:
    def __init__(self, genislik, yukseklik):
        self._genislik = genislik
        self._yukseklik = yukseklik

    @property
    def genislik(self):
        return self._genislik

    @genislik.setter
    def genislik(self, deger):
        if deger < 0:
            raise ValueError('Genişlik negatif olamaz')
        self._genislik = deger

    @property
    def alan(self):
        return self._genislik * self._yukseklik

