```python
import unittest
from unittest.mock import Mock, patch, MagicMock
import pytest

# Test edilecek kodlar
class HesapMakinesi:
    def topla(self, a, b):
        return a + b

    def cikar(self, a, b):
        return a - b

    def carp(self, a, b):
        return a * b

    def bol(self, a, b):
        if b == 0:
            raise ValueError('Sıfıra bölme!')
        return a / b

# unittest ile test
class TestHesapMakinesi(unittest.TestCase):

    def setUp(self):
        """Her test öncesi çalışır"""
        self.hesap = HesapMakinesi()

    def tearDown(self):
        """Her test sonrası çalışır"""
        pass

    def test_topla(self):
        self.assertEqual(self.hesap.topla(2, 3), 5)
        self.assertEqual(self.hesap.topla(-1, 1), 0)

    def test_cikar(self):
        self.assertEqual(self.hesap.cikar(5, 3), 2)

    def test_carp(self):
        self.assertEqual(self.hesap.carp(2, 3), 6)

    def test_bol(self):
        self.assertEqual(self.hesap.bol(6, 2), 3)
        with self.assertRaises(ValueError):
            self.hesap.bol(1, 0)

# pytest ile test (daha pratik)
def test_topla():
    hesap = HesapMakinesi()
    assert hesap.topla(2, 3) == 5
    assert hesap.topla(-1, 1) == 0

@pytest.mark.parametrize('a,b,beklenen', [
    (2, 3, 5),
    (-1, 1, 0),
    (0, 0, 0),
])
def test_topla_parametrize(a, b, beklenen):
    hesap = HesapMakinesi()
    assert hesap.topla(a, b) == beklenen

# Mock örneği
class APIClient:
    def __init__(self, session):
        self.session = session

    def get_user(self, user_id):
        response = self.session.get(f'/users/{user_id}')
        return response.json()

class TestAPIClient(unittest.TestCase):

    @patch('requests.Session')
    def test_get_user(self, mock_session):
        # Mock hazırla
        mock_response = Mock()
        mock_response.json.return_value = {'id': 1, 'name': 'Test'}
        mock_session.return_value.get.return_value = mock_response

        # Test et
        client = APIClient(mock_session.return_value)
        result = client.get_user(1)

        # Doğrula
        self.assertEqual(result['name'], 'Test')
        mock_session.return_value.get.assert_called_once_with('/users/1')

